# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
import os

# Set database configurations from environment variables
rds_host  = os.environ['RDS_HOST']
name = os.environ['RDS_USERNAME']
password = os.environ['RDS_PASSWORD']
db_name = os.environ['RDS_DB_NAME']
port = os.environ['RDS_PORT']

def lambda_handler(event, context):
    # Parse the search parameter from the event
    search_param = json.loads(event['body'])['searchParam'] if 'searchParam' in json.loads(event['body']) else ''
    
    try:
        conn = pymysql.connect(rds_host, user=name, passwd=password, db=db_name, port=int(port), connect_timeout=5)
        
        with conn.cursor() as cursor:
            # Prepare a SQL query string based on the search parameter
            sql = f"SELECT * FROM Products WHERE ProductName LIKE '%{search_param}%' OR Description LIKE '%{search_param}%'"
            
            cursor.execute(sql)
            
            result = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'body': json.dumps({"message": "Search Successful", "result": str(result)})
        }
    
    except Exception as e:
        print("ERROR: Could not connect to MySql instance.", e)
        
        return {
            'statusCode': 500,
            'body': json.dumps({"message": "Error while searching", "error": str(e)})
        }